parameters.jsCode:
// Extract Typeform fields
const formResponse = $input.first().json.form_response;
const answers = formResponse.answers;

// Map Typeform fields to Airtable schema
const waitlistEntry = {
  waitlist_id: `wait_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  restaurant_name: answers.find(a => a.field.ref === 'restaurant_name')?.text || '',
  contact_name: answers.find(a => a.field.ref === 'contact_name')?.text || '',
  contact_email: answers.find(a => a.field.ref === 'contact_email')?.email || '',
  contact_phone: answers.find(a => a.field.ref === 'contact_phone')?.phone_number || '',
  city: answers.find(a => a.field.ref === 'city')?.text || '',
  current_rating: answers.find(a => a.field.ref === 'current_rating')?.choice?.label || '',
  google_business_url: answers.find(a => a.field.ref === 'google_url')?.url || '',
  monthly_review_volume: answers.find(a => a.field.ref === 'review_volume')?.choice?.label || '',
  submitted_at: formResponse.submitted_at,
  application_status: 'New',
  source: 'Typeform'
};

return { json: waitlistEntry };

